	t.Setenv("TIDE_LEADER_LEASE_SECONDS", "30")
	got := atoiOrDefault("TIDE_LEADER_LEASE_SECONDS", 15)
	if got != 30 {
		t.Fatalf("atoiOrDefault: got %d, want 30", got)
	}
}

