	t.Setenv("TIDE_LEADER_LEASE_SECONDS", "")
	got := atoiOrDefault("TIDE_LEADER_LEASE_SECONDS", 15)
	if got != 15 {
		t.Fatalf("atoiOrDefault: got %d, want 15", got)
	}
}

