func TestAtoiOrDefault_Garbage(t *testing.T) {
	t.Setenv("TIDE_LEADER_LEASE_SECONDS", "not-a-number")
	got := atoiOrDefault("TIDE_LEADER_LEASE_SECONDS", 15)
	if got != 15 {
		t.Fatalf("atoiOrDefault: got %d, want 15 (garbage env falls back)", got)
	}
}

